function calculateScore(inputs) {
  const { 
    dataQualityScore, 
    dataAccessibilityScore, 
    workforceAILiteracy, 
    upskillingInvestment, 
    innovationCultureScore, 
    changeManagementReadiness, 
    aiStrategyClarity, 
    leadershipBuyIn 
  } = inputs;

  // Ensure inputs are within valid range and convert to numbers
  const dq = Math.max(1, Math.min(5, Number(dataQualityScore)));
  const da = Math.max(1, Math.min(5, Number(dataAccessibilityScore)));
  const wal = Math.max(0, Math.min(100, Number(workforceAILiteracy)));
  const ui = Math.max(0, Math.min(5000, Number(upskillingInvestment)));
  const ic = Math.max(1, Math.min(5, Number(innovationCultureScore)));
  const cm = Math.max(1, Math.min(5, Number(changeManagementReadiness)));
  const asc = Math.max(1, Math.min(5, Number(aiStrategyClarity)));
  const lb = Math.max(1, Math.min(5, Number(leadershipBuyIn)));

  // 1. Calculate Data Infrastructure Score (out of 100)
  // Average of two 1-5 scores, scaled to 100 (each point is 20 points)
  const dataInfrastructureScore = ((dq + da) / 2) * 20;

  // 2. Calculate Workforce & Skills Score (out of 100)
  // 50% from AI Literacy, 50% from Upskilling Investment
  const aiLiteracyContribution = (wal / 100) * 50; // Max 50 points
  const upskillingContribution = (ui / 5000) * 50; // Max 50 points, capped at 5000
  const workforceScore = aiLiteracyContribution + upskillingContribution;

  // 3. Calculate Organizational Culture Score (out of 100)
  // Average of two 1-5 scores, scaled to 100
  const cultureScore = ((ic + cm) / 2) * 20;

  // 4. Calculate Strategic Alignment Score (out of 100)
  // Average of two 1-5 scores, scaled to 100
  const strategyScore = ((asc + lb) / 2) * 20;

  // 5. Calculate Overall AI Adoption Readiness Score (average of the four category scores)
  const aiReadinessScore = (dataInfrastructureScore + workforceScore + cultureScore + strategyScore) / 4;

  return {
    aiReadinessScore: Math.round(aiReadinessScore * 10) / 10,
    dataInfrastructureScore: Math.round(dataInfrastructureScore * 10) / 10,
    workforceScore: Math.round(workforceScore * 10) / 10,
    cultureScore: Math.round(cultureScore * 10) / 10,
    strategyScore: Math.round(strategyScore * 10) / 10
  };
}
